1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_DISCOUNT = 0.2;
4	const LOYALTY_YEARS = 2;
5	const FOLLOWUP_DISCOUNT = 0.15;
6	const CURSE_SURCHARGE = 0.5;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PRICE = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCH_CLAIM_THRESHOLD = 8;
14	const HIGH_ENCH_REIMBURSEMENT = 0.5;
15	
16	type Item = {
17	  type: string;
18	  material?: string;
19	  enchantment?: number;
20	  cursed?: boolean;
21	};
22	
23	type Damage = { itemType: string; amount: number };
24	
25	type Customer = { yearsWithMHPCO: number };
26	
27	type QuoteStep = { op: "quote"; items: Item[] };
28	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
29	type Step = QuoteStep | ClaimStep;
30	
31	type Scenario = { customer: Customer; steps: Step[] };
32	
33	type QuoteResult = { premium: number };
34	type ClaimResult = { payout: number; remainingCap: number };
35	
36	const BASE_PREMIUMS: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
44	
45	const INSURANCE_VALUES: Record<string, number> = {
46	  sword: 1000,
47	  amulet: 600,
48	  staff: 800,
49	  potion: 400,
50	  rune: 250,
51	  moonstone: 250,
52	};
53	
54	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
55	
56	const itemBase = (item: Item): number => BASE_PREMIUMS[item.type];
57	
58	const itemSurcharge = (item: Item): number => {
59	  const base = itemBase(item);
60	  const curse = item.cursed ? base * CURSE_SURCHARGE : 0;
61	  const highEnch =
62	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE : 0;
63	  return curse + highEnch;
64	};
65	
66	const componentGroupBase = (count: number, perItem: number): number => {
67	  if (count === BLOCK_SIZE) return BLOCK_PRICE;
68	  return count * perItem;
69	};
70	
71	const policyBaseAndSurcharges = (items: Item[]): { base: number; surcharges: number } => {
72	  const componentCounts = new Map<string, number>();
73	  let mainBase = 0;
74	  let surcharges = 0;
75	  for (const item of items) {
76	    if (COMPONENT_TYPES.has(item.type)) {
77	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
78	    } else {
79	      mainBase += itemBase(item);
80	      surcharges += itemSurcharge(item);
81	    }
82	  }
83	  let componentBase = 0;
84	  for (const [type, count] of componentCounts) {
85	    componentBase += componentGroupBase(count, BASE_PREMIUMS[type]);
86	  }
87	  return { base: mainBase + componentBase, surcharges };
88	};
89	
90	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
91	  const { base, surcharges } = policyBaseAndSurcharges(items);
92	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
93	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS ? base * LOYALTY_DISCOUNT : 0;
94	  const followUp = isFollowUp ? base * FOLLOWUP_DISCOUNT : 0;
95	  return Math.ceil(base + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
96	};
97	
98	const insuranceSum = (items: Item[]): number =>
99	  items.reduce((sum, it) => sum + INSURANCE_VALUES[it.type], 0);
100	
101	type Policy = { items: Item[]; remainingCap: number };
102	
103	const damagePayout = (damage: Damage, item: Item): number => {
104	  const reimbursable =
105	    (item.enchantment ?? 0) >= HIGH_ENCH_CLAIM_THRESHOLD
106	      ? damage.amount * HIGH_ENCH_REIMBURSEMENT
107	      : damage.amount;
108	  return Math.max(0, reimbursable - DEDUCTIBLE);
109	};
110	
111	const processClaim = (policy: Policy, damages: Damage[]): ClaimResult => {
112	  const payout = damages.reduce((sum, d) => {
113	    const item = policy.items.find((it) => it.type === d.itemType)!;
114	    return sum + damagePayout(d, item);
115	  }, 0);
116	  policy.remainingCap -= payout;
117	  return { payout, remainingCap: policy.remainingCap };
118	};
119	
120	export const runScenario = (input: unknown): unknown => {
121	  const scenario = input as Scenario;
122	  const policies: Policy[] = [];
123	  let quoteCount = 0;
124	  const results: (QuoteResult | ClaimResult)[] = scenario.steps.map((step) => {
125	    if (step.op === "quote") {
126	      const isFollowUp = quoteCount > 0;
127	      quoteCount += 1;
128	      const items = step.items;
129	      const premium = quotePremium(items, scenario.customer, isFollowUp);
130	      policies.push({ items, remainingCap: insuranceSum(items) * CAP_MULTIPLIER });
131	      return { premium };
132	    }
133	    return processClaim(policies[step.policy], step.incident.damages);
134	  });
135	  return { results };
136	};
